import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { User, Mail, Lock, UserCheck, ArrowRight } from 'lucide-react';

const Registro = () => {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    nombre: '',
    apellido: '',
    nombreUsuario: '',
    correo: '',
    password: '',
    rol: 'cliente' // Valor inicial
  });

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleRegistro = (e) => {
    e.preventDefault();
    
    // 1. Obtener base de datos simulada de usuarios
    const usuarios = JSON.parse(localStorage.getItem('usuarios-db') || "[]");

    // 2. Validaciones de unicidad (Profesional)
    if (usuarios.find(u => u.correo === formData.correo)) {
      return alert("Este correo ya está registrado.");
    }
    if (usuarios.find(u => u.nombreUsuario === formData.nombreUsuario)) {
      return alert("El nombre de usuario ya está en uso.");
    }

    // 3. Crear el objeto de usuario final (Esquema de DB real)
    const nuevoUsuario = {
      id: `user-${Date.now()}`,
      ...formData,
      fechaRegistro: new Date().toISOString(),
      estado: 'activo'
    };

    // 4. Guardar y redireccionar
    usuarios.push(nuevoUsuario);
    localStorage.setItem('usuarios-db', JSON.stringify(usuarios));

    alert("¡Cuenta creada con éxito! Ya puedes iniciar sesión.");
    navigate('/login');
  };

  return (
    <div style={containerStyle}>
      <div style={cardStyle}>
        <div style={{ textAlign: 'center', marginBottom: '25px' }}>
          <h2 style={{ fontSize: '1.8rem', color: '#1e293b', marginBottom: '8px' }}>Crear una cuenta</h2>
          <p style={{ color: '#64748b' }}>Unite a la comunidad de ofertas más grande</p>
        </div>

        <form onSubmit={handleRegistro}>
          <div style={rowStyle}>
            <div style={{ flex: 1 }}>
              <label style={labelStyle}>Nombre</label>
              <input name="nombre" style={inputStyle} required onChange={handleChange} placeholder="Ej: Juan" />
            </div>
            <div style={{ flex: 1 }}>
              <label style={labelStyle}>Apellido</label>
              <input name="apellido" style={inputStyle} required onChange={handleChange} placeholder="Ej: Pérez" />
            </div>
          </div>

          <div style={inputGroup}>
            <label style={labelStyle}>Nombre de Usuario</label>
            <div style={inputWrapper}>
              <User size={18} color="#94a3b8" />
              <input name="nombreUsuario" style={rawInput} required onChange={handleChange} placeholder="juanperez_22" />
            </div>
          </div>

          <div style={inputGroup}>
            <label style={labelStyle}>Correo Electrónico</label>
            <div style={inputWrapper}>
              <Mail size={18} color="#94a3b8" />
              <input name="correo" type="email" style={rawInput} required onChange={handleChange} placeholder="email@ejemplo.com" />
            </div>
          </div>

          <div style={inputGroup}>
            <label style={labelStyle}>Contraseña</label>
            <div style={inputWrapper}>
              <Lock size={18} color="#94a3b8" />
              <input name="password" type="password" style={rawInput} required onChange={handleChange} placeholder="••••••••" />
            </div>
          </div>

          <div style={inputGroup}>
            <label style={labelStyle}>¿Cómo usarás la plataforma?</label>
            <div style={inputWrapper}>
              <UserCheck size={18} color="#94a3b8" />
              <select name="rol" style={rawInput} value={formData.rol} onChange={handleChange}>
                <option value="cliente">Quiero buscar ofertas (Cliente)</option>
                <option value="vendedor">Quiero publicar mis ofertas (Vendedor)</option>
              </select>
            </div>
          </div>

          <button type="submit" style={btnSubmit}>
            Registrarme <ArrowRight size={18} />
          </button>
        </form>

        <p style={footerText}>
          ¿Ya tienes cuenta? <Link to="/login" style={linkStyle}>Inicia sesión</Link>
        </p>
      </div>
    </div>
  );
};

// --- ESTILOS ---
const containerStyle = { display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '90vh', background: '#f8fafc', padding: '20px' };
const cardStyle = { background: 'white', padding: '40px', borderRadius: '24px', boxShadow: '0 10px 25px rgba(0,0,0,0.05)', width: '100%', maxWidth: '500px' };
const rowStyle = { display: 'flex', gap: '15px', marginBottom: '15px' };
const inputGroup = { marginBottom: '15px' };
const labelStyle = { display: 'block', fontSize: '0.85rem', fontWeight: '600', color: '#475569', marginBottom: '6px' };
const inputWrapper = { display: 'flex', alignItems: 'center', gap: '10px', background: '#f1f5f9', padding: '0 15px', borderRadius: '12px', border: '1px solid #e2e8f0' };
const rawInput = { width: '100%', padding: '12px 0', border: 'none', background: 'transparent', outline: 'none', fontSize: '0.95rem', color: '#1e293b' };
const inputStyle = { ...rawInput, background: '#f1f5f9', padding: '12px 15px', borderRadius: '12px', border: '1px solid #e2e8f0' };
const btnSubmit = { width: '100%', padding: '14px', background: '#e67e22', color: 'white', border: 'none', borderRadius: '12px', fontWeight: 'bold', cursor: 'pointer', fontSize: '1rem', marginTop: '15px', display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '10px' };
const footerText = { textAlign: 'center', marginTop: '20px', color: '#64748b', fontSize: '0.9rem' };
const linkStyle = { color: '#e67e22', fontWeight: 'bold', textDecoration: 'none' };

export default Registro;
